            >
              {isOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </div>

      {/* Full-screen Mobile Menu */}
      <div className={`lg:hidden fixed inset-0 bg-slate-950 z-[110] transition-all duration-700 ease-[cubic-bezier(0.16, 1, 0.3, 1)] ${
