          {navLinks.map((link, idx) => (
            <Link
              key={link.path}
              to={link.path}
              className={`block text-3xl sm:text-4xl font-serif font-bold transition-all transform duration-500 ${
                isOpen ? 'translate-x-0 opacity-100' : 'translate-x-12 opacity-0'
